async (page) => {
  await page.goto('http://localhost:7777/ponder');
  await page.waitForTimeout(1000);

  // Find preview elements with the expected styling
  const previews = await page.evaluate(() => {
    const allEls = Array.from(document.querySelectorAll('*'));
    const previewEls = allEls.filter(el => {
      const cls = el.className || '';
      return typeof cls === 'string' && cls.includes('mt-0.5') && cls.includes('italic');
    });
    return previewEls.map(el => ({
      tag: el.tagName,
      text: el.textContent?.trim().slice(0, 100),
      className: el.className?.slice(0, 120)
    }));
  });

  return { url: page.url(), previews };
}

