async (page) => {
  // Check the floating nav buttons
  const navInfo = await page.evaluate(() => {
    const prevBtn = document.querySelector('[aria-label="Previous entry"]');
    const nextBtn = document.querySelector('[aria-label="Next entry"]');

    const getInfo = (btn) => {
      if (!btn) return null;
      const rect = btn.getBoundingClientRect();
      const style = window.getComputedStyle(btn);
      return {
        exists: true,
        disabled: btn.disabled,
        visible: rect.width > 0 && rect.height > 0,
        rect: { top: Math.round(rect.top), left: Math.round(rect.left), width: Math.round(rect.width), height: Math.round(rect.height) },
        opacity: style.opacity,
        className: btn.className.slice(0, 100)
      };
    };

    const container = document.querySelector('[class*="md:hidden"][class*="fixed"][class*="bottom-16"]');
    return {
      prevBtn: getInfo(prevBtn),
      nextBtn: getInfo(nextBtn),
      container: container ? {
        exists: true,
        className: container.className.slice(0, 100),
        rect: { top: Math.round(container.getBoundingClientRect().top), left: Math.round(container.getBoundingClientRect().left) }
      } : null,
      viewport: { width: window.innerWidth, height: window.innerHeight }
    };
  });
  return navInfo;
}

